  ('lib.lead.lead_assigned_to_wrong_territory', 'lead', 'agent', 'manager_review', 'לידים: הכנת חתימה (טיוטה)', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'זוהה צורך בחתימה (ליד assigned to wrong טריטוריה). הכנת טיוטת בקשה מסודרת מקצרת זמן וממקדת את הלקוח. חשוב: ZONO מכין טיוטה בלבד — השליחה והחתימה נשארות בידי האחראי האנושי.', 'לידים: הכנת חתימה (טיוטה)', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'טיוטת חתימה הוכנה להליד. ודא בדיקה ואישור אנושי לפני שליחה.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'עיכוב בחתימה מאריך את מועד הסגירה.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', 'לידים: ליד assigned to wrong טריטוריה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', null, null, null, 'אוטומציה (לידים/ליד assigned to wrong טריטוריה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.lead.lead_should_be_routed_to_stronger_agent', 'lead', 'agent', 'manager_review', 'לידים: בחינת ניתוב להליד', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'הליד מתאים לבחינת ניתוב (ליד should be routed to stronger סוכן). שיוך נכון בין לקוח לסוכן בעל התמחות וזמינות מתאימים מעלה מהותית את סיכויי הסגירה. מומלץ לבחון את ההתאמה ולאשר שיוך מיטבי.', 'לידים: בחינת ניתוב להליד', 'בחן את התאמת הליד לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'בחן את התאמת הליד לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'הליד מועמד לניתוב מחדש. ודא שיוך לסוכן החזק והמתאים ביותר לאזור/לצורך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'שיוך לא מיטבי שורף הזדמנות אצל הלקוח.', 'הליד משויך לסוכן המתאים ביותר ומקודם.', 'לידים: ליד should be routed to stronger סוכן. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הליד משויך לסוכן המתאים ביותר ומקודם.', null, null, null, 'אוטומציה (לידים/ליד should be routed to stronger סוכן) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.lead.lead_from_high_performing_channel', 'lead', 'agent', 'growth_opportunity', 'לידים: הליד מחובר להזדמנות נוספת (וריאנט 6)', 'הליד מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הליד מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הליד מחובר להקשר נוסף במערכת (ליד from high-performing channel). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'לידים: הליד מחובר להזדמנות נוספת (וריאנט 6)', 'נצל את החיבור של הליד (ליד from high-performing channel) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של הליד (ליד from high-performing channel) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'הליד מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'לידים: ליד from high-performing channel. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (לידים/ליד from high-performing channel) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
