  ('lib.seller.seller_linked_to_property', 'seller', 'agent', 'growth_opportunity', 'מוכרים: המוכר מחובר להזדמנות נוספת', 'המוכר מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'המוכר מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'המוכר מחובר להקשר נוסף במערכת (מוכר linked to נכס). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'מוכרים: המוכר מחובר להזדמנות נוספת', 'נצל את החיבור של המוכר (מוכר linked to נכס) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של המוכר (מוכר linked to נכס) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'המוכר מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'מוכרים: מוכר linked to נכס. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (מוכרים/מוכר linked to נכס) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_decision_maker_missing', 'seller', 'agent', 'follow_up_required', 'מוכרים: פער בטיפול בהמוכר (וריאנט 4)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'המוכר מציג פער (מוכר decision maker חסר) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'מוכרים: פער בטיפול בהמוכר (וריאנט 4)', 'השלם את החסר בהמוכר (מוכר decision maker חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהמוכר (מוכר decision maker חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהמוכר. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והמוכר חוזר למסלול טיפול פעיל.', 'מוכרים: מוכר decision maker חסר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והמוכר חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (מוכרים/מוכר decision maker חסר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.seller.seller_signer_missing', 'seller', 'agent', 'manager_review', 'מוכרים: הכנת חתימה (טיוטה)', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'זוהה צורך בחתימה (מוכר signer חסר). הכנת טיוטת בקשה מסודרת מקצרת זמן וממקדת את הלקוח. חשוב: ZONO מכין טיוטה בלבד — השליחה והחתימה נשארות בידי האחראי האנושי.', 'מוכרים: הכנת חתימה (טיוטה)', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'טיוטת חתימה הוכנה להמוכר. ודא בדיקה ואישור אנושי לפני שליחה.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'עיכוב בחתימה מאריך את מועד הסגירה.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', 'מוכרים: מוכר signer חסר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', null, null, null, 'אוטומציה (מוכרים/מוכר signer חסר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
