  ('lib.seller.seller_property_has_deal_risk', 'seller', 'agent', 'deal_risk', 'מוכרים: סיכון פעיל בהמוכר', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'המוכר נמצא בסיכון (מוכר נכס has עסקה סיכון). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'מוכרים: סיכון פעיל בהמוכר', 'טפל בשורש הסיכון בהמוכר (מוכר נכס has עסקה סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהמוכר (מוכר נכס has עסקה סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'המוכר בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'מוכרים: מוכר נכס has עסקה סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (מוכרים/מוכר נכס has עסקה סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.seller.seller_needs_document_checklist', 'seller', 'agent', 'deal_risk', 'מוכרים: מסמך חסר חוסם התקדמות (וריאנט 2)', 'חסרים מסמכים שעלולים לחסום התקדמות.', 'חסרים מסמכים שעלולים לחסום התקדמות.', 'זוהה חוסר במסמך/אישור הנדרש להמשך (מוכר needs מסמך רשימת בדיקה). מסמכים חסרים חוסמים פרסום, חתימה או התקדמות עסקה. מומלץ להשלים את רשימת המסמכים ולוודא שאין חסם פתוח.', 'מוכרים: מסמך חסר חוסם התקדמות (וריאנט 2)', 'השלם את רשימת המסמכים הנדרשת להמוכר (מוכר needs מסמך רשימת בדיקה) כדי לפתוח את החסם להמשך.', 'השלם את רשימת המסמכים הנדרשת להמוכר (מוכר needs מסמך רשימת בדיקה) כדי לפתוח את החסם להמשך.', 'קיים חסם מסמכים בהמוכר. ודא השלמה כדי שלא לעכב פרסום או עסקה.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'מסמך חסר עלול לעצור עסקה ברגע הקריטי.', 'רשימת המסמכים מושלמת והחסם נפתח.', 'מוכרים: מוכר needs מסמך רשימת בדיקה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'רשימת המסמכים מושלמת והחסם נפתח.', null, null, null, 'אוטומציה (מוכרים/מוכר needs מסמך רשימת בדיקה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.seller.seller_needs_signature_draft', 'seller', 'agent', 'manager_review', 'מוכרים: הכנת חתימה (טיוטה) (וריאנט 2)', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'זוהה צורך בחתימה (מוכר needs חתימה draft). הכנת טיוטת בקשה מסודרת מקצרת זמן וממקדת את הלקוח. חשוב: ZONO מכין טיוטה בלבד — השליחה והחתימה נשארות בידי האחראי האנושי.', 'מוכרים: הכנת חתימה (טיוטה) (וריאנט 2)', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'טיוטת חתימה הוכנה להמוכר. ודא בדיקה ואישור אנושי לפני שליחה.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'עיכוב בחתימה מאריך את מועד הסגירה.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', 'מוכרים: מוכר needs חתימה draft. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', null, null, null, 'אוטומציה (מוכרים/מוכר needs חתימה draft) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.seller.seller_should_receive_marketing_report', 'seller', 'agent', 'quick_win', 'מוכרים: המוכר בשל לקבלת ערך ממוקד (וריאנט 2)', 'הגיע הזמן לספק להמוכר ערך ממוקד ומותאם.', 'הגיע הזמן לספק להמוכר ערך ממוקד ומותאם.', 'המוכר בשל לקבלת תוצר ערך מותאם (מוכר should receive שיווק report). אספקת תובנה או חבילה רלוונטית בזמן הנכון מחזקת אמון ומקדמת החלטה. מומלץ להכין את התוצר ולהציגו באופן אישי.', 'מוכרים: המוכר בשל לקבלת ערך ממוקד (וריאנט 2)', 'הכן להמוכר את התוצר המתאים (מוכר should receive שיווק report) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הכן להמוכר את התוצר המתאים (מוכר should receive שיווק report) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'המוכר ראוי לאספקת ערך ממוקד. ודא שהתוצר הוכן ונמסר באיכות גבוהה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'אספקת ערך בעיתוי הנכון מחזקת אמון ומקצרת את מסלול ההחלטה.', 'המוכר מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'מוכרים: מוכר should receive שיווק report. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המוכר מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר should receive שיווק report. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא מוכר should receive שיווק report. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (מוכרים/מוכר should receive שיווק report) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_should_receive_buyer_demand_update', 'seller', 'agent', 'quick_win', 'מוכרים: המוכר בשל לקבלת ערך ממוקד (וריאנט 3)', 'הגיע הזמן לספק להמוכר ערך ממוקד ומותאם.', 'הגיע הזמן לספק להמוכר ערך ממוקד ומותאם.', 'המוכר בשל לקבלת תוצר ערך מותאם (מוכר should receive קונה demand update). אספקת תובנה או חבילה רלוונטית בזמן הנכון מחזקת אמון ומקדמת החלטה. מומלץ להכין את התוצר ולהציגו באופן אישי.', 'מוכרים: המוכר בשל לקבלת ערך ממוקד (וריאנט 3)', 'הכן להמוכר את התוצר המתאים (מוכר should receive קונה demand update) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הכן להמוכר את התוצר המתאים (מוכר should receive קונה demand update) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'המוכר ראוי לאספקת ערך ממוקד. ודא שהתוצר הוכן ונמסר באיכות גבוהה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'אספקת ערך בעיתוי הנכון מחזקת אמון ומקצרת את מסלול ההחלטה.', 'המוכר מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'מוכרים: מוכר should receive קונה demand update. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המוכר מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר should receive קונה demand update. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא מוכר should receive קונה demand update. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (מוכרים/מוכר should receive קונה demand update) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_should_be_asked_for_price_adjustment', 'seller', 'agent', 'manager_review', 'מוכרים: בחינת תמחור נדרשת (וריאנט 4)', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'זוהתה סוגיית תמחור במוכרים (מוכר should be asked for מחיר adjustment). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'מוכרים: בחינת תמחור נדרשת (וריאנט 4)', 'הכן ניתוח עסקאות משווה להמוכר, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה להמוכר, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'מוכרים: מוכר should be asked for מחיר adjustment. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר should be asked for מחיר adjustment. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (מוכרים/מוכר should be asked for מחיר adjustment) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.seller.seller_should_approve_distribution', 'seller', 'agent', 'high_priority', 'מוכרים: מוכר should approve הפצה', 'זוהה אירוע במוכרים שמצדיק פעולה יזומה.', 'זוהה אירוע במוכרים שמצדיק פעולה יזומה.', 'זוהה אירוע במוכרים (מוכר should approve הפצה) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'מוכרים: מוכר should approve הפצה', 'בחן את ההקשר של מוכר should approve הפצה בהמוכר, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של מוכר should approve הפצה בהמוכר, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע במוכרים (מוכר should approve הפצה) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'מוכרים: מוכר should approve הפצה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (מוכרים/מוכר should approve הפצה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_has_acquisition_opportunity', 'seller', 'agent', 'revenue_opportunity', 'מוכרים: הזדמנות שכדאי לממש', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות במוכרים (מוכר has גיוס הזדמנות). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'מוכרים: הזדמנות שכדאי לממש', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות במוכרים ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'מוכרים: מוכר has גיוס הזדמנות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (מוכרים/מוכר has גיוס הזדמנות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_should_be_converted_from_external_listing', 'seller', 'agent', 'growth_opportunity', 'מוכרים: התקדמות חיובית למינוף (וריאנט 2)', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'המוכר עבר אבן דרך חיובית (מוכר should be הומר from external listing). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'מוכרים: התקדמות חיובית למינוף (וריאנט 2)', 'נצל את ההצלחה בהמוכר: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהמוכר: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'המוכר רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'מוכרים: מוכר should be הומר from external listing. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר should be הומר from external listing. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא מוכר should be הומר from external listing. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (מוכרים/מוכר should be הומר from external listing) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_belongs_to_hot_territory', 'seller', 'agent', 'high_priority', 'מוכרים: המוכר בכוונה גבוהה — חלון הזדמנות', 'המוכר מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'המוכר מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'המוכר מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (מוכר belongs to חם טריטוריה). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'מוכרים: המוכר בכוונה גבוהה — חלון הזדמנות', 'המוכר חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'המוכר חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'המוכר בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'המוכר מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'מוכרים: מוכר belongs to חם טריטוריה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המוכר מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר belongs to חם טריטוריה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (מוכרים/מוכר belongs to חם טריטוריה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_belongs_to_competitor_dominated_territory', 'seller', 'agent', 'growth_opportunity', 'מוכרים: המוכר מחובר להזדמנות נוספת (וריאנט 2)', 'המוכר מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'המוכר מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'המוכר מחובר להקשר נוסף במערכת (מוכר belongs to competitor-dominated טריטוריה). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'מוכרים: המוכר מחובר להזדמנות נוספת (וריאנט 2)', 'נצל את החיבור של המוכר (מוכר belongs to competitor-dominated טריטוריה) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של המוכר (מוכר belongs to competitor-dominated טריטוריה) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'המוכר מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'מוכרים: מוכר belongs to competitor-dominated טריטוריה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (מוכרים/מוכר belongs to competitor-dominated טריטוריה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
