  ('lib.property.property_marketing_score_low', 'property', 'agent', 'high_priority', 'נכסים: שינוי ציון/ביצוע בהנכס', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'עודכן ציון או מדד ביצועים עבור הנכס (נכס שיווק score נמוך). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'נכסים: שינוי ציון/ביצוע בהנכס', 'בדוק מה הוביל לשינוי הציון בהנכס (נכס שיווק score נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהנכס (נכס שיווק score נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הנכס השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'נכסים: נכס שיווק score נמוך. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (נכסים/נכס שיווק score נמוך) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_distribution_missing', 'property', 'agent', 'follow_up_required', 'נכסים: פער בטיפול בהנכס (וריאנט 8)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הנכס מציג פער (נכס הפצה חסר) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'נכסים: פער בטיפול בהנכס (וריאנט 8)', 'השלם את החסר בהנכס (נכס הפצה חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס הפצה חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'נכסים: נכס הפצה חסר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (נכסים/נכס הפצה חסר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_should_enter_daily_publishing', 'property', 'agent', 'high_priority', 'נכסים: נכס should enter daily publishing', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס should enter daily publishing) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס should enter daily publishing', 'בחן את ההקשר של נכס should enter daily publishing בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס should enter daily publishing בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס should enter daily publishing) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס should enter daily publishing. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס should enter daily publishing) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_should_get_recommendation_package', 'property', 'agent', 'quick_win', 'נכסים: הנכס בשל לקבלת ערך ממוקד', 'הגיע הזמן לספק להנכס ערך ממוקד ומותאם.', 'הגיע הזמן לספק להנכס ערך ממוקד ומותאם.', 'הנכס בשל לקבלת תוצר ערך מותאם (נכס should get המלצה חבילה). אספקת תובנה או חבילה רלוונטית בזמן הנכון מחזקת אמון ומקדמת החלטה. מומלץ להכין את התוצר ולהציגו באופן אישי.', 'נכסים: הנכס בשל לקבלת ערך ממוקד', 'הכן להנכס את התוצר המתאים (נכס should get המלצה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הכן להנכס את התוצר המתאים (נכס should get המלצה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הנכס ראוי לאספקת ערך ממוקד. ודא שהתוצר הוכן ונמסר באיכות גבוהה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'אספקת ערך בעיתוי הנכון מחזקת אמון ומקצרת את מסלול ההחלטה.', 'הנכס מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'נכסים: נכס should get המלצה חבילה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס should get המלצה חבילה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא נכס should get המלצה חבילה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (נכסים/נכס should get המלצה חבילה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_has_matching_buyers', 'property', 'agent', 'revenue_opportunity', 'נכסים: הזדמנות שכדאי לממש', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות בנכסים (נכס has matching buyers). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'נכסים: הזדמנות שכדאי לממש', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בנכסים ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'נכסים: נכס has matching buyers. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (נכסים/נכס has matching buyers) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_has_high_value_buyer', 'property', 'agent', 'high_priority', 'נכסים: נכס has high-value קונה', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס has high-value קונה) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס has high-value קונה', 'בחן את ההקשר של נכס has high-value קונה בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס has high-value קונה בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס has high-value קונה) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס has high-value קונה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס has high-value קונה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_has_deal_created', 'property', 'agent', 'quick_win', 'נכסים: הנכס חדש נכנס למערכת (וריאנט 2)', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 2)', 'נכסים: הנכס חדש נכנס למערכת (וריאנט 2)', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הנכס חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'נכסים: נכס has עסקה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס has עסקה נוצר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (נכסים/נכס has עסקה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_deal_stalled', 'property', 'agent', 'deal_risk', 'נכסים: סיכון פעיל בהנכס', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'הנכס נמצא בסיכון (נכס עסקה stalled). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'נכסים: סיכון פעיל בהנכס', 'טפל בשורש הסיכון בהנכס (נכס עסקה stalled) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהנכס (נכס עסקה stalled) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הנכס בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'נכסים: נכס עסקה stalled. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (נכסים/נכס עסקה stalled) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_forecast_changed', 'property', 'agent', 'high_priority', 'נכסים: נכס תחזית changed', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס תחזית changed) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס תחזית changed', 'בחן את ההקשר של נכס תחזית changed בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס תחזית changed בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס תחזית changed) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס תחזית changed. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס תחזית changed) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_should_update_seller_portal', 'property', 'agent', 'follow_up_required', 'נכסים: הנכס זקוק לעדכון/קידום', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הנכס הגיע לנקודה שמחייבת עדכון או קידום שלב (נכס should update מוכר פורטל). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'נכסים: הנכס זקוק לעדכון/קידום', 'בצע את העדכון/הקידום הנדרש להנכס (נכס should update מוכר פורטל), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש להנכס (נכס should update מוכר פורטל), וודא שהשלב הבא ברור ומתואם.', 'הנכס ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', 'נכסים: נכס should update מוכר פורטל. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (נכסים/נכס should update מוכר פורטל) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_should_refresh_website_listing', 'property', 'agent', 'follow_up_required', 'נכסים: הנכס זקוק לעדכון/קידום (וריאנט 2)', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הנכס הגיע לנקודה שמחייבת עדכון או קידום שלב (נכס should refresh אתר listing). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'נכסים: הנכס זקוק לעדכון/קידום (וריאנט 2)', 'בצע את העדכון/הקידום הנדרש להנכס (נכס should refresh אתר listing), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש להנכס (נכס should refresh אתר listing), וודא שהשלב הבא ברור ומתואם.', 'הנכס ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', 'נכסים: נכס should refresh אתר listing. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (נכסים/נכס should refresh אתר listing) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_status_changed', 'property', 'agent', 'follow_up_required', 'נכסים: הנכס זקוק לעדכון/קידום (וריאנט 3)', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הנכס הגיע לנקודה שמחייבת עדכון או קידום שלב (נכס סטטוס changed). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'נכסים: הנכס זקוק לעדכון/קידום (וריאנט 3)', 'בצע את העדכון/הקידום הנדרש להנכס (נכס סטטוס changed), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש להנכס (נכס סטטוס changed), וודא שהשלב הבא ברור ומתואם.', 'הנכס ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', 'נכסים: נכס סטטוס changed. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (נכסים/נכס סטטוס changed) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_sold', 'property', 'agent', 'growth_opportunity', 'נכסים: התקדמות חיובית למינוף', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הנכס עבר אבן דרך חיובית (נכס sold). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'נכסים: התקדמות חיובית למינוף', 'נצל את ההצלחה בהנכס: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהנכס: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'הנכס רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'נכסים: נכס sold. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס sold. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא נכס sold. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (נכסים/נכס sold) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
