  ('lib.property.property_archived', 'property', 'agent', 'high_priority', 'נכסים: נכס archived', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס archived) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס archived', 'בחן את ההקשר של נכס archived בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס archived בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס archived) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס archived. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס archived) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_exclusive_expiring', 'property', 'agent', 'follow_up_required', 'נכסים: פער בטיפול בהנכס (וריאנט 9)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הנכס מציג פער (נכס exclusive expiring) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'נכסים: פער בטיפול בהנכס (וריאנט 9)', 'השלם את החסר בהנכס (נכס exclusive expiring) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס exclusive expiring) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'נכסים: נכס exclusive expiring. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (נכסים/נכס exclusive expiring) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_duplicate_suspected', 'property', 'agent', 'manager_review', 'נכסים: בעיית איכות נתונים (וריאנט 2)', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים/מערכת (נכס כפילות suspected). נתונים שגויים פוגעים באמינות ההמלצות והדוחות. מומלץ לטפל בשורש הבעיה כדי לשמור על דיוק ההחלטות בכל המערכת.', 'נכסים: בעיית איכות נתונים (וריאנט 2)', 'טפל בבעיית הנתונים (נכס כפילות suspected) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'טפל בבעיית הנתונים (נכס כפילות suspected) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'קיימת בעיית איכות נתונים (נכס כפילות suspected). ודא טיפול כדי לשמר אמינות החלטות ודוחות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'נתונים שגויים מתפשטים ופוגעים בכל שכבת ההחלטה.', 'איכות הנתונים משוחזרת והדיוק נשמר.', 'נכסים: נכס כפילות suspected. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'איכות הנתונים משוחזרת והדיוק נשמר.', null, null, null, 'אוטומציה (נכסים/נכס כפילות suspected) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
