  ('lib.property.property_acquisition_opportunity', 'property', 'agent', 'revenue_opportunity', 'נכסים: הזדמנות שכדאי לממש (וריאנט 2)', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות בנכסים (נכס גיוס הזדמנות). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'נכסים: הזדמנות שכדאי לממש (וריאנט 2)', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בנכסים ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'נכסים: נכס גיוס הזדמנות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (נכסים/נכס גיוס הזדמנות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_in_hot_street', 'property', 'agent', 'high_priority', 'נכסים: הנכס בכוונה גבוהה — חלון הזדמנות', 'הנכס מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הנכס מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הנכס מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (נכס in חם רחוב). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'נכסים: הנכס בכוונה גבוהה — חלון הזדמנות', 'הנכס חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הנכס חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הנכס בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הנכס מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'נכסים: נכס in חם רחוב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס in חם רחוב. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (נכסים/נכס in חם רחוב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_in_weak_territory', 'property', 'agent', 'deal_risk', 'נכסים: סיכון פעיל בהנכס (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'הנכס נמצא בסיכון (נכס in חלש טריטוריה). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'נכסים: סיכון פעיל בהנכס (וריאנט 2)', 'טפל בשורש הסיכון בהנכס (נכס in חלש טריטוריה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהנכס (נכס in חלש טריטוריה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הנכס בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'נכסים: נכס in חלש טריטוריה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (נכסים/נכס in חלש טריטוריה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_in_competitor_threat_area', 'property', 'agent', 'high_priority', 'נכסים: נכס in מתחרה threat אזור', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס in מתחרה threat אזור) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס in מתחרה threat אזור', 'בחן את ההקשר של נכס in מתחרה threat אזור בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס in מתחרה threat אזור בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס in מתחרה threat אזור) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס in מתחרה threat אזור. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס in מתחרה threat אזור) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_requires_manager_review', 'property', 'agent', 'manager_review', 'נכסים: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'הנכס הגיע לרף שמצדיק מעורבות ניהולית (נכס requires מנהל בדיקה). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'נכסים: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להנכס והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להנכס והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הנכס דורש החלטה ניהולית (נכס requires מנהל בדיקה). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'נכסים: נכס requires מנהל בדיקה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (נכסים/נכס requires מנהל בדיקה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.match.match_created', 'match', 'executive', 'quick_win', 'התאמות: ההתאמה חדש נכנס למערכת', 'ההתאמה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'ההתאמה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'מבט מנהלים: ההתאמה נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'התאמות: ההתאמה חדש נכנס למערכת', 'ההתאמה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'ההתאמה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט ההתאמה חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'ההתאמה מטופל, משויך ומקודם לצעד הבא במסלול.', 'התאמות: התאמה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההתאמה מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (התאמות/התאמה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
