  ('lib.match.match_objection_added', 'match', 'executive', 'quick_win', 'התאמות: ההתאמה חדש נכנס למערכת (וריאנט 2)', 'ההתאמה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'ההתאמה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'מבט מנהלים: ההתאמה נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 2)', 'התאמות: ההתאמה חדש נכנס למערכת (וריאנט 2)', 'ההתאמה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'ההתאמה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט ההתאמה חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'ההתאמה מטופל, משויך ומקודם לצעד הבא במסלול.', 'התאמות: התאמה התנגדות added. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההתאמה מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (התאמות/התאמה התנגדות added) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.match.match_objection_unresolved', 'match', 'executive', 'deal_risk', 'התאמות: סיכון פעיל בההתאמה (וריאנט 3)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: ההתאמה נמצא בסיכון (התאמה התנגדות unresolved). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'התאמות: סיכון פעיל בההתאמה (וריאנט 3)', 'טפל בשורש הסיכון בההתאמה (התאמה התנגדות unresolved) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בההתאמה (התאמה התנגדות unresolved) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'ההתאמה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'התאמות: התאמה התנגדות unresolved. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (התאמות/התאמה התנגדות unresolved) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_moved_to_negotiation', 'match', 'executive', 'follow_up_required', 'התאמות: ההתאמה זקוק לעדכון/קידום', 'ההתאמה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'ההתאמה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'מבט מנהלים: ההתאמה הגיע לנקודה שמחייבת עדכון או קידום שלב (התאמה moved to negotiation). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'התאמות: ההתאמה זקוק לעדכון/קידום', 'בצע את העדכון/הקידום הנדרש לההתאמה (התאמה moved to negotiation), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש לההתאמה (התאמה moved to negotiation), וודא שהשלב הבא ברור ומתואם.', 'ההתאמה ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'ההתאמה מעודכן, מסונכרן וממשיך ברצף תקין.', 'התאמות: התאמה moved to negotiation. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההתאמה מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (התאמות/התאמה moved to negotiation) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
