  ('lib.territory.territory_transaction_spike', 'territory', 'acquisition', 'high_priority', 'טריטוריה: הטריטוריה בכוונה גבוהה — חלון הזדמנות (וריאנט 2)', 'הטריטוריה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הטריטוריה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'זווית גיוס: הטריטוריה מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (טריטוריה עסקה spike). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'טריטוריה: הטריטוריה בכוונה גבוהה — חלון הזדמנות (וריאנט 2)', 'הטריטוריה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הטריטוריה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הטריטוריה בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הטריטוריה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'טריטוריה: טריטוריה עסקה spike. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הטריטוריה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה עסקה spike) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.territory_recommendation_density_high', 'territory', 'acquisition', 'high_priority', 'טריטוריה: שינוי ציון/ביצוע בהטריטוריה', 'חל שינוי בציון/בביצועים של הטריטוריה שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הטריטוריה שמשנה תעדוף.', 'זווית גיוס: עודכן ציון או מדד ביצועים עבור הטריטוריה (טריטוריה המלצה density גבוה). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'טריטוריה: שינוי ציון/ביצוע בהטריטוריה', 'בדוק מה הוביל לשינוי הציון בהטריטוריה (טריטוריה המלצה density גבוה), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהטריטוריה (טריטוריה המלצה density גבוה), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הטריטוריה השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'טריטוריה: טריטוריה המלצה density גבוה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה המלצה density גבוה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
