  ('lib.territory.territory_no_assigned_agent', 'territory', 'acquisition', 'manager_review', 'טריטוריה: הכנת חתימה (טיוטה)', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'זווית גיוס: זוהה צורך בחתימה (טריטוריה no assigned סוכן). הכנת טיוטת בקשה מסודרת מקצרת זמן וממקדת את הלקוח. חשוב: ZONO מכין טיוטה בלבד — השליחה והחתימה נשארות בידי האחראי האנושי.', 'טריטוריה: הכנת חתימה (טיוטה)', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'טיוטת חתימה הוכנה להטריטוריה. ודא בדיקה ואישור אנושי לפני שליחה.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־18,000 ₪ בעסקה ממוצעת מסוג זה.', 'עיכוב בחתימה מאריך את מועד הסגירה.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', 'טריטוריה: טריטוריה no assigned סוכן. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה no assigned סוכן) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.territory.territory_weak_agent_ownership', 'territory', 'acquisition', 'deal_risk', 'טריטוריה: סיכון פעיל בהטריטוריה (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זווית גיוס: הטריטוריה נמצא בסיכון (טריטוריה חלש סוכן ownership). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'טריטוריה: סיכון פעיל בהטריטוריה (וריאנט 2)', 'טפל בשורש הסיכון בהטריטוריה (טריטוריה חלש סוכן ownership) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהטריטוריה (טריטוריה חלש סוכן ownership) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הטריטוריה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־18,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'טריטוריה: טריטוריה חלש סוכן ownership. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה חלש סוכן ownership) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.territory.territory_strong_agent_ownership', 'territory', 'acquisition', 'high_priority', 'טריטוריה: טריטוריה strong סוכן ownership', 'זוהה אירוע בטריטוריה שמצדיק פעולה יזומה.', 'זוהה אירוע בטריטוריה שמצדיק פעולה יזומה.', 'זווית גיוס: זוהה אירוע בטריטוריה (טריטוריה strong סוכן ownership) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'טריטוריה: טריטוריה strong סוכן ownership', 'בחן את ההקשר של טריטוריה strong סוכן ownership בהטריטוריה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של טריטוריה strong סוכן ownership בהטריטוריה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בטריטוריה (טריטוריה strong סוכן ownership) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'טריטוריה: טריטוריה strong סוכן ownership. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה strong סוכן ownership) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
