  ('lib.acquisition.acquisition_follow_up_due', 'acquisition', 'acquisition', 'follow_up_required', 'גיוס מלאי: ההזדמנות דורש מעקב יזום', 'נדרש מעקב יזום כדי לשמר מומנטום מול ההזדמנות.', 'נדרש מעקב יזום כדי לשמר מומנטום מול ההזדמנות.', 'זווית גיוס: ההזדמנות דורש מעקב יזום (גיוס מעקב due). היעדר המשכיות הוא הגורם המוביל לאובדן עסקאות. מומלץ לבצע מעקב מקצועי שממשיך את השיחה הקודמת ומקדם צעד מוחשי.', 'גיוס מלאי: ההזדמנות דורש מעקב יזום', 'בצע מעקב לההזדמנות שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'בצע מעקב לההזדמנות שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'ההזדמנות ממתין למעקב. ודא שהמעגל נסגר כדי לא לאבד התקדמות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'כל יום ללא מעקב מקטין את סבירות ההמרה.', 'המעקב בוצע וההזדמנות מקודם עם צעד המשך מתואם.', 'גיוס מלאי: גיוס מעקב due. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'המעקב בוצע וההזדמנות מקודם עם צעד המשך מתואם.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מעקב due) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_follow_up_missed', 'acquisition', 'acquisition', 'deal_risk', 'גיוס מלאי: סיכון פעיל בההזדמנות', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זווית גיוס: ההזדמנות נמצא בסיכון (גיוס מעקב missed). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'גיוס מלאי: סיכון פעיל בההזדמנות', 'טפל בשורש הסיכון בההזדמנות (גיוס מעקב missed) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בההזדמנות (גיוס מעקב missed) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'ההזדמנות בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'גיוס מלאי: גיוס מעקב missed. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מעקב missed) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_promoted_to_crm', 'acquisition', 'acquisition', 'growth_opportunity', 'גיוס מלאי: התקדמות חיובית למינוף', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'זווית גיוס: ההזדמנות עבר אבן דרך חיובית (גיוס promoted to crm). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'גיוס מלאי: התקדמות חיובית למינוף', 'נצל את ההצלחה בההזדמנות: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בההזדמנות: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'ההזדמנות רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'גיוס מלאי: גיוס promoted to crm. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס promoted to crm) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_marked_not_relevant', 'acquisition', 'acquisition', 'customer_risk', 'גיוס מלאי: אירוע שדורש סגירה מסודרת', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זווית גיוס: ההזדמנות עבר אירוע שלילי (גיוס marked לא relevant). חשוב לסגור מסודר, ללמוד את הסיבה, ולבחון אם יש מסלול הצלה. טיפול נכון גם באירוע שלילי שומר על מוניטין ועל פוטנציאל עתידי.', 'גיוס מלאי: אירוע שדורש סגירה מסודרת', 'סגור מסודר את ההזדמנות, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'סגור מסודר את ההזדמנות, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'ההזדמנות ברצף שלילי. ודא סגירה מסודרת ולמידה לשימור איכות התהליך.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'סגירה לא מסודרת פוגעת בנתונים ובמוניטין.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', 'גיוס מלאי: גיוס marked לא relevant. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס marked לא relevant) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_stale', 'acquisition', 'acquisition', 'follow_up_required', 'גיוס מלאי: פער בטיפול בההזדמנות', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זווית גיוס: ההזדמנות מציג פער (גיוס מיושן) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'גיוס מלאי: פער בטיפול בההזדמנות', 'השלם את החסר בההזדמנות (גיוס מיושן) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בההזדמנות (גיוס מיושן) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בההזדמנות. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר וההזדמנות חוזר למסלול טיפול פעיל.', 'גיוס מלאי: גיוס מיושן. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר וההזדמנות חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מיושן) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_price_changed', 'acquisition', 'acquisition', 'manager_review', 'גיוס מלאי: בחינת תמחור נדרשת', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'זווית גיוס: זוהתה סוגיית תמחור בגיוס מלאי (גיוס מחיר changed). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'גיוס מלאי: בחינת תמחור נדרשת', 'הכן ניתוח עסקאות משווה לההזדמנות, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה לההזדמנות, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'גיוס מלאי: גיוס מחיר changed. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מחיר changed) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_duplicate_suspected', 'acquisition', 'acquisition', 'manager_review', 'גיוס מלאי: בעיית איכות נתונים', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זווית גיוס: זוהתה בעיית איכות נתונים/מערכת (גיוס כפילות suspected). נתונים שגויים פוגעים באמינות ההמלצות והדוחות. מומלץ לטפל בשורש הבעיה כדי לשמור על דיוק ההחלטות בכל המערכת.', 'גיוס מלאי: בעיית איכות נתונים', 'טפל בבעיית הנתונים (גיוס כפילות suspected) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'טפל בבעיית הנתונים (גיוס כפילות suspected) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'קיימת בעיית איכות נתונים (גיוס כפילות suspected). ודא טיפול כדי לשמר אמינות החלטות ודוחות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'נתונים שגויים מתפשטים ופוגעים בכל שכבת ההחלטה.', 'איכות הנתונים משוחזרת והדיוק נשמר.', 'גיוס מלאי: גיוס כפילות suspected. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'איכות הנתונים משוחזרת והדיוק נשמר.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס כפילות suspected) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_seller_phone_missing', 'acquisition', 'acquisition', 'follow_up_required', 'גיוס מלאי: פער בטיפול בההזדמנות (וריאנט 2)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זווית גיוס: ההזדמנות מציג פער (גיוס מוכר טלפון חסר) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'גיוס מלאי: פער בטיפול בההזדמנות (וריאנט 2)', 'השלם את החסר בההזדמנות (גיוס מוכר טלפון חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בההזדמנות (גיוס מוכר טלפון חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בההזדמנות. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר וההזדמנות חוזר למסלול טיפול פעיל.', 'גיוס מלאי: גיוס מוכר טלפון חסר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר וההזדמנות חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מוכר טלפון חסר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_source_low_quality', 'acquisition', 'acquisition', 'growth_opportunity', 'גיוס מלאי: ההזדמנות מחובר להזדמנות נוספת', 'ההזדמנות מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'ההזדמנות מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'זווית גיוס: ההזדמנות מחובר להקשר נוסף במערכת (גיוס source נמוך quality). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'גיוס מלאי: ההזדמנות מחובר להזדמנות נוספת', 'נצל את החיבור של ההזדמנות (גיוס source נמוך quality) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של ההזדמנות (גיוס source נמוך quality) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'ההזדמנות מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'גיוס מלאי: גיוס source נמוך quality. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס source נמוך quality) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_should_create_seller_profile', 'acquisition', 'acquisition', 'high_priority', 'גיוס מלאי: גיוס should create מוכר profile', 'זוהה אירוע בגיוס מלאי שמצדיק פעולה יזומה.', 'זוהה אירוע בגיוס מלאי שמצדיק פעולה יזומה.', 'זווית גיוס: זוהה אירוע בגיוס מלאי (גיוס should create מוכר profile) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'גיוס מלאי: גיוס should create מוכר profile', 'בחן את ההקשר של גיוס should create מוכר profile בההזדמנות, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של גיוס should create מוכר profile בההזדמנות, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בגיוס מלאי (גיוס should create מוכר profile) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'גיוס מלאי: גיוס should create מוכר profile. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס should create מוכר profile) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
