  ('lib.acquisition.acquisition_should_notify_manager', 'acquisition', 'acquisition', 'manager_review', 'גיוס מלאי: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'זווית גיוס: ההזדמנות הגיע לרף שמצדיק מעורבות ניהולית (גיוס should notify מנהל). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'גיוס מלאי: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים לההזדמנות והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים לההזדמנות והעבר לאישור/ליווי ניהולי לפני פעולה.', 'ההזדמנות דורש החלטה ניהולית (גיוס should notify מנהל). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'גיוס מלאי: גיוס should notify מנהל. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס should notify מנהל) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_creates_revenue_opportunity', 'acquisition', 'acquisition', 'revenue_opportunity', 'גיוס מלאי: הזדמנות שכדאי לממש (וריאנט 4)', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זווית גיוס: זוהתה הזדמנות בגיוס מלאי (גיוס creates הכנסות הזדמנות). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'גיוס מלאי: הזדמנות שכדאי לממש (וריאנט 4)', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בגיוס מלאי ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'גיוס מלאי: גיוס creates הכנסות הזדמנות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס creates הכנסות הזדמנות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_related_to_community_opportunity', 'acquisition', 'acquisition', 'revenue_opportunity', 'גיוס מלאי: הזדמנות שכדאי לממש (וריאנט 5)', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זווית גיוס: זוהתה הזדמנות בגיוס מלאי (גיוס related to קהילה הזדמנות). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'גיוס מלאי: הזדמנות שכדאי לממש (וריאנט 5)', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בגיוס מלאי ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'גיוס מלאי: גיוס related to קהילה הזדמנות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס related to קהילה הזדמנות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_related_to_territory_gap', 'acquisition', 'acquisition', 'growth_opportunity', 'גיוס מלאי: ההזדמנות מחובר להזדמנות נוספת (וריאנט 2)', 'ההזדמנות מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'ההזדמנות מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'זווית גיוס: ההזדמנות מחובר להקשר נוסף במערכת (גיוס related to טריטוריה פער). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'גיוס מלאי: ההזדמנות מחובר להזדמנות נוספת (וריאנט 2)', 'נצל את החיבור של ההזדמנות (גיוס related to טריטוריה פער) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של ההזדמנות (גיוס related to טריטוריה פער) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'ההזדמנות מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'גיוס מלאי: גיוס related to טריטוריה פער. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס related to טריטוריה פער) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_should_update_decision_brain', 'acquisition', 'acquisition', 'follow_up_required', 'גיוס מלאי: ההזדמנות זקוק לעדכון/קידום', 'ההזדמנות זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'ההזדמנות זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'זווית גיוס: ההזדמנות הגיע לנקודה שמחייבת עדכון או קידום שלב (גיוס should update decision brain). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'גיוס מלאי: ההזדמנות זקוק לעדכון/קידום', 'בצע את העדכון/הקידום הנדרש לההזדמנות (גיוס should update decision brain), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש לההזדמנות (גיוס should update decision brain), וודא שהשלב הבא ברור ומתואם.', 'ההזדמנות ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'ההזדמנות מעודכן, מסונכרן וממשיך ברצף תקין.', 'גיוס מלאי: גיוס should update decision brain. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס should update decision brain) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.marketing.marketing_profile_created', 'marketing', 'marketing', 'quick_win', 'שיווק והפצה: הנכס חדש נכנס למערכת', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'זווית שיווק: הנכס נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'שיווק והפצה: הנכס חדש נכנס למערכת', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הנכס חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'שיווק והפצה: שיווק profile נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (שיווק והפצה/שיווק profile נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.marketing.marketing_score_low', 'marketing', 'marketing', 'high_priority', 'שיווק והפצה: שינוי ציון/ביצוע בהנכס', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'זווית שיווק: עודכן ציון או מדד ביצועים עבור הנכס (שיווק score נמוך). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'שיווק והפצה: שינוי ציון/ביצוע בהנכס', 'בדוק מה הוביל לשינוי הציון בהנכס (שיווק score נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהנכס (שיווק score נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הנכס השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'שיווק והפצה: שיווק score נמוך. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (שיווק והפצה/שיווק score נמוך) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
