  ('lib.social.social_lead_no_follow_up', 'social', 'agent', 'follow_up_required', 'לידים חברתיים: פער בטיפול בהפנייה', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הפנייה מציג פער (חברתי ליד no מעקב) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'לידים חברתיים: פער בטיפול בהפנייה', 'השלם את החסר בהפנייה (חברתי ליד no מעקב) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהפנייה (חברתי ליד no מעקב) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהפנייה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והפנייה חוזר למסלול טיפול פעיל.', 'לידים חברתיים: חברתי ליד no מעקב. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והפנייה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (לידים חברתיים/חברתי ליד no מעקב) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.social.social_lead_source_community_high_performing', 'social', 'agent', 'high_priority', 'לידים חברתיים: הפנייה בכוונה גבוהה — חלון הזדמנות (וריאנט 2)', 'הפנייה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הפנייה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הפנייה מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (חברתי ליד source קהילה גבוה performing). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'לידים חברתיים: הפנייה בכוונה גבוהה — חלון הזדמנות (וריאנט 2)', 'הפנייה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הפנייה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הפנייה בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הפנייה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'לידים חברתיים: חברתי ליד source קהילה גבוה performing. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הפנייה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא חברתי ליד source קהילה גבוה performing. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, 'תודה על פנייתך. סוכן/ת מטעמנו ייצור/תיצור קשר בהקדם להמשך אישי בנושא חברתי ליד source קהילה גבוה performing.', 'אוטומציה (לידים חברתיים/חברתי ליד source קהילה גבוה performing) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.social.social_lead_asks_price', 'social', 'agent', 'manager_review', 'לידים חברתיים: בחינת תמחור נדרשת', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'זוהתה סוגיית תמחור בלידים חברתיים (חברתי ליד asks מחיר). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'לידים חברתיים: בחינת תמחור נדרשת', 'הכן ניתוח עסקאות משווה להפנייה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה להפנייה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'לידים חברתיים: חברתי ליד asks מחיר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא חברתי ליד asks מחיר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (לידים חברתיים/חברתי ליד asks מחיר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.social.social_lead_asks_viewing', 'social', 'agent', 'high_priority', 'לידים חברתיים: חברתי ליד asks צפייה בנכס', 'זוהה אירוע בלידים חברתיים שמצדיק פעולה יזומה.', 'זוהה אירוע בלידים חברתיים שמצדיק פעולה יזומה.', 'זוהה אירוע בלידים חברתיים (חברתי ליד asks צפייה בנכס) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'לידים חברתיים: חברתי ליד asks צפייה בנכס', 'בחן את ההקשר של חברתי ליד asks צפייה בנכס בהפנייה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של חברתי ליד asks צפייה בנכס בהפנייה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בלידים חברתיים (חברתי ליד asks צפייה בנכס) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'לידים חברתיים: חברתי ליד asks צפייה בנכס. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (לידים חברתיים/חברתי ליד asks צפייה בנכס) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
