  ('lib.revenue.revenue_should_notify_manager', 'revenue', 'executive', 'manager_review', 'הכנסות ותחזית: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'מבט מנהלים: הצנרת הגיע לרף שמצדיק מעורבות ניהולית (הכנסות should notify מנהל). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'הכנסות ותחזית: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להצנרת והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להצנרת והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הצנרת דורש החלטה ניהולית (הכנסות should notify מנהל). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־30,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'הכנסות ותחזית: הכנסות should notify מנהל. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (הכנסות ותחזית/הכנסות should notify מנהל) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.revenue.revenue_creates_decision_brain_signal', 'revenue', 'executive', 'manager_review', 'הכנסות ותחזית: הכנת חתימה (טיוטה)', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'מבט מנהלים: זוהה צורך בחתימה (הכנסות creates decision brain signal). הכנת טיוטת בקשה מסודרת מקצרת זמן וממקדת את הלקוח. חשוב: ZONO מכין טיוטה בלבד — השליחה והחתימה נשארות בידי האחראי האנושי.', 'הכנסות ותחזית: הכנת חתימה (טיוטה)', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'טיוטת חתימה הוכנה להצנרת. ודא בדיקה ואישור אנושי לפני שליחה.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־30,000 ₪ בעסקה ממוצעת מסוג זה.', 'עיכוב בחתימה מאריך את מועד הסגירה.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', 'הכנסות ותחזית: הכנסות creates decision brain signal. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', null, null, null, 'אוטומציה (הכנסות ותחזית/הכנסות creates decision brain signal) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.team.agent_twin_created', 'team', 'manager', 'quick_win', 'צוות וניתוב: הסוכן חדש נכנס למערכת', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'לתשומת לב הניהול: הסוכן נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'צוות וניתוב: הסוכן חדש נכנס למערכת', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הסוכן חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', 'צוות וניתוב: סוכן twin נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן twin נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.agent_performance_changed', 'team', 'manager', 'high_priority', 'צוות וניתוב: שינוי ציון/ביצוע בהסוכן', 'חל שינוי בציון/בביצועים של הסוכן שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הסוכן שמשנה תעדוף.', 'לתשומת לב הניהול: עודכן ציון או מדד ביצועים עבור הסוכן (סוכן ביצועים changed). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'צוות וניתוב: שינוי ציון/ביצוע בהסוכן', 'בדוק מה הוביל לשינוי הציון בהסוכן (סוכן ביצועים changed), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהסוכן (סוכן ביצועים changed), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הסוכן השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'צוות וניתוב: סוכן ביצועים changed. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן ביצועים changed) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.agent_overloaded', 'team', 'manager', 'high_priority', 'צוות וניתוב: סוכן עומס יתר', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'לתשומת לב הניהול: זוהה אירוע בצוות וניתוב (סוכן עומס יתר) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'צוות וניתוב: סוכן עומס יתר', 'בחן את ההקשר של סוכן עומס יתר בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של סוכן עומס יתר בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בצוות וניתוב (סוכן עומס יתר) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'צוות וניתוב: סוכן עומס יתר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן עומס יתר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
