  ('lib.team.agent_strongest_territory_changed', 'team', 'manager', 'high_priority', 'צוות וניתוב: סוכן strongest טריטוריה changed', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'לתשומת לב הניהול: זוהה אירוע בצוות וניתוב (סוכן strongest טריטוריה changed) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'צוות וניתוב: סוכן strongest טריטוריה changed', 'בחן את ההקשר של סוכן strongest טריטוריה changed בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של סוכן strongest טריטוריה changed בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בצוות וניתוב (סוכן strongest טריטוריה changed) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'צוות וניתוב: סוכן strongest טריטוריה changed. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן strongest טריטוריה changed) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.agent_weakness_detected', 'team', 'manager', 'deal_risk', 'צוות וניתוב: סיכון פעיל בהסוכן', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'לתשומת לב הניהול: הסוכן נמצא בסיכון (סוכן weakness detected). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'צוות וניתוב: סיכון פעיל בהסוכן', 'טפל בשורש הסיכון בהסוכן (סוכן weakness detected) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהסוכן (סוכן weakness detected) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הסוכן בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'צוות וניתוב: סוכן weakness detected. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן weakness detected) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.team.agent_coaching_signal', 'team', 'manager', 'manager_review', 'צוות וניתוב: הכנת חתימה (טיוטה)', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'נדרשת הכנת חתימה — טיוטה בלבד, ללא שליחה אוטומטית.', 'לתשומת לב הניהול: זוהה צורך בחתימה (סוכן חניכה signal). הכנת טיוטת בקשה מסודרת מקצרת זמן וממקדת את הלקוח. חשוב: ZONO מכין טיוטה בלבד — השליחה והחתימה נשארות בידי האחראי האנושי.', 'צוות וניתוב: הכנת חתימה (טיוטה)', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'עיין בטיוטת בקשת החתימה שהוכנה, התאם פרטים, ושלח ידנית לאחר אישור.', 'טיוטת חתימה הוכנה להסוכן. ודא בדיקה ואישור אנושי לפני שליחה.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'עיכוב בחתימה מאריך את מועד הסגירה.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', 'צוות וניתוב: סוכן חניכה signal. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'טיוטת החתימה מאושרת ונשלחת ידנית בזמן.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן חניכה signal) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.team.lead_routing_profile_created', 'team', 'manager', 'quick_win', 'צוות וניתוב: הסוכן חדש נכנס למערכת (וריאנט 2)', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'לתשומת לב הניהול: הסוכן נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 2)', 'צוות וניתוב: הסוכן חדש נכנס למערכת (וריאנט 2)', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הסוכן חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', 'צוות וניתוב: ליד ניתוב profile נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (צוות וניתוב/ליד ניתוב profile נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.lead_routed_recommendation', 'team', 'manager', 'manager_review', 'צוות וניתוב: בחינת ניתוב להסוכן', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'לתשומת לב הניהול: הסוכן מתאים לבחינת ניתוב (ליד routed המלצה). שיוך נכון בין לקוח לסוכן בעל התמחות וזמינות מתאימים מעלה מהותית את סיכויי הסגירה. מומלץ לבחון את ההתאמה ולאשר שיוך מיטבי.', 'צוות וניתוב: בחינת ניתוב להסוכן', 'בחן את התאמת הסוכן לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'בחן את התאמת הסוכן לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'הסוכן מועמד לניתוב מחדש. ודא שיוך לסוכן החזק והמתאים ביותר לאזור/לצורך.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'שיוך לא מיטבי שורף הזדמנות אצל הלקוח.', 'הסוכן משויך לסוכן המתאים ביותר ומקודם.', 'צוות וניתוב: ליד routed המלצה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הסוכן משויך לסוכן המתאים ביותר ומקודם.', null, null, null, 'אוטומציה (צוות וניתוב/ליד routed המלצה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.routing_candidate_changed', 'team', 'manager', 'high_priority', 'צוות וניתוב: ניתוב candidate changed', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'לתשומת לב הניהול: זוהה אירוע בצוות וניתוב (ניתוב candidate changed) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'צוות וניתוב: ניתוב candidate changed', 'בחן את ההקשר של ניתוב candidate changed בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של ניתוב candidate changed בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בצוות וניתוב (ניתוב candidate changed) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'צוות וניתוב: ניתוב candidate changed. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (צוות וניתוב/ניתוב candidate changed) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.routing_confidence_low', 'team', 'manager', 'high_priority', 'צוות וניתוב: שינוי ציון/ביצוע בהסוכן (וריאנט 2)', 'חל שינוי בציון/בביצועים של הסוכן שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הסוכן שמשנה תעדוף.', 'לתשומת לב הניהול: עודכן ציון או מדד ביצועים עבור הסוכן (ניתוב confidence נמוך). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'צוות וניתוב: שינוי ציון/ביצוע בהסוכן (וריאנט 2)', 'בדוק מה הוביל לשינוי הציון בהסוכן (ניתוב confidence נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהסוכן (ניתוב confidence נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הסוכן השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'צוות וניתוב: ניתוב confidence נמוך. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (צוות וניתוב/ניתוב confidence נמוך) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
