  ('lib.team.manager_override_routing', 'team', 'manager', 'manager_review', 'צוות וניתוב: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'לתשומת לב הניהול: הסוכן הגיע לרף שמצדיק מעורבות ניהולית (מנהל override ניתוב). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'צוות וניתוב: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להסוכן והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להסוכן והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הסוכן דורש החלטה ניהולית (מנהל override ניתוב). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'צוות וניתוב: מנהל override ניתוב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (צוות וניתוב/מנהל override ניתוב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.agent_missed_follow_up', 'team', 'manager', 'deal_risk', 'צוות וניתוב: סיכון פעיל בהסוכן (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'לתשומת לב הניהול: הסוכן נמצא בסיכון (סוכן missed מעקב). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'צוות וניתוב: סיכון פעיל בהסוכן (וריאנט 2)', 'טפל בשורש הסיכון בהסוכן (סוכן missed מעקב) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהסוכן (סוכן missed מעקב) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הסוכן בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'צוות וניתוב: סוכן missed מעקב. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן missed מעקב) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.team.agent_completed_task_streak', 'team', 'manager', 'growth_opportunity', 'צוות וניתוב: התקדמות חיובית למינוף', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'לתשומת לב הניהול: הסוכן עבר אבן דרך חיובית (סוכן completed משימה streak). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'צוות וניתוב: התקדמות חיובית למינוף', 'נצל את ההצלחה בהסוכן: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהסוכן: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'הסוכן רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'צוות וניתוב: סוכן completed משימה streak. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן completed משימה streak) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.agent_pipeline_risk', 'team', 'manager', 'deal_risk', 'צוות וניתוב: סיכון פעיל בהסוכן (וריאנט 3)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'לתשומת לב הניהול: הסוכן נמצא בסיכון (סוכן צנרת סיכון). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'צוות וניתוב: סיכון פעיל בהסוכן (וריאנט 3)', 'טפל בשורש הסיכון בהסוכן (סוכן צנרת סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהסוכן (סוכן צנרת סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הסוכן בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'צוות וניתוב: סוכן צנרת סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן צנרת סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.team.agent_revenue_opportunity', 'team', 'manager', 'revenue_opportunity', 'צוות וניתוב: הזדמנות שכדאי לממש', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'לתשומת לב הניהול: זוהתה הזדמנות בצוות וניתוב (סוכן הכנסות הזדמנות). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'צוות וניתוב: הזדמנות שכדאי לממש', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בצוות וניתוב ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'צוות וניתוב: סוכן הכנסות הזדמנות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן הכנסות הזדמנות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.agent_website_lead_created', 'team', 'manager', 'quick_win', 'צוות וניתוב: הסוכן חדש נכנס למערכת (וריאנט 3)', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'לתשומת לב הניהול: הסוכן נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 3)', 'צוות וניתוב: הסוכן חדש נכנס למערכת (וריאנט 3)', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הסוכן חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', 'צוות וניתוב: סוכן אתר ליד נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן אתר ליד נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.agent_portal_activity', 'team', 'manager', 'customer_risk', 'צוות וניתוב: הסוכן גילה מעורבות פעילה', 'הסוכן גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'הסוכן גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'לתשומת לב הניהול: הסוכן ביצע פעולת מעורבות (סוכן פורטל activity). מעורבות יזומה היא אות חם: הלקוח עוסק באופן פעיל. מומלץ לנצל את המומנטום בפנייה רלוונטית שממשיכה בדיוק מהנקודה שבה הוא התעניין.', 'צוות וניתוב: הסוכן גילה מעורבות פעילה', 'הסוכן מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'הסוכן מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'זוהתה מעורבות פעילה של הסוכן. ודא מענה מהיר כדי להמיר עניין לפעולה.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'מענה תוך זמן קצר ממעורבות מגדיל מהותית את סיכויי ההמרה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', 'צוות וניתוב: סוכן פורטל activity. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', null, null, null, 'אוטומציה (צוות וניתוב/סוכן פורטל activity) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.team_health_changed', 'team', 'manager', 'high_priority', 'צוות וניתוב: team health changed', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'לתשומת לב הניהול: זוהה אירוע בצוות וניתוב (team health changed) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'צוות וניתוב: team health changed', 'בחן את ההקשר של team health changed בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של team health changed בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בצוות וניתוב (team health changed) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'צוות וניתוב: team health changed. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (צוות וניתוב/team health changed) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
