  title_he=excluded.title_he, subtitle_he=excluded.subtitle_he, short_description_he=excluded.short_description_he,
  full_description_he=excluded.full_description_he, task_title_he=excluded.task_title_he, task_description_he=excluded.task_description_he,
  agent_guidance_he=excluded.agent_guidance_he, manager_guidance_he=excluded.manager_guidance_he, revenue_impact_he=excluded.revenue_impact_he,
  urgency_reason_he=excluded.urgency_reason_he, expected_outcome_he=excluded.expected_outcome_he, decision_brain_summary_he=excluded.decision_brain_summary_he,
  success_definition_he=excluded.success_definition_he, client_draft_message_he=excluded.client_draft_message_he, portal_message_he=excluded.portal_message_he,
  website_message_he=excluded.website_message_he, audit_log_text_he=excluded.audit_log_text_he;

-- ── message variants (client/portal/website drafts; never auto-sent) ──────────
delete from public.automation_message_variants where template_key like 'lib.%';
